def perceive(data):
    out = {}
    if isinstance(data, dict):
        if data.get("filing_type") is not None:
            out["filing_type"] = str(data["filing_type"])
        dl = data.get("deadline", data.get("due_in_days"))
        if dl is not None:
            out["deadline"] = int(dl)
    return out
